insert into public.questions (number, category, question, options, correct_index) values (1, 'Word', '''Find and Replace'' qayerda joylashgan?', array['''Home'' menyusi ichida, yoki Ctrl + H yordamida chaqiriladi.','Onlayn matn hujjatlarini yaratish va birgalikda tahrirlash.','Word''da Insert → Page Number opsiyasidan.','Bir xil hujjatga har xil ma''lumotlarni joylab, ommaviy yuborish imkonini beradi.'], 0) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (2, 'Word', '''Mail Merge'' funksiyasi qaysi vazifani bajaradi?', array['Word''da Insert → Page Number opsiyasidan.','''Home'' menyusi ichida, yoki Ctrl + H yordamida chaqiriladi.','Bir xil hujjatga har xil ma''lumotlarni joylab, ommaviy yuborish imkonini beradi.','Matn tahrirlash, formatlash, sahifalash.'], 2) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (3, 'Word', '''Page Layout'' menyusi nima uchun kerak?', array['Onlayn matn hujjatlarini yaratish va birgalikda tahrirlash.','Insert → Page Number menyusidan.','Sahifa formatini (chekka, o''lcham, orientatsiya, ustunlar) sozlash uchun.','Ctrl + S yoki menyuda ''Save'' opsiyasini tanlash orqali.'], 2) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (4, 'PowerPoint', 'Animatsiya nima uchun kerak?', array['Slayd.','PowerPoint''da ovozli izohlar qo''shish uchun.','Slayddagi elementlarga harakat berib, kontentni jonlantirish uchun.','Vizual imkoniyatli taqdimotlar yaratish uchun.'], 2) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (5, 'Excel', 'Autosum tugmasi nima uchun kerak?', array['Katta hajmdagi ma''lumotni tahlil qilish va ko''rgazmali hisobot berish uchun.','Excel''da tez yig''indi (SUM) funksiyasini ishlatish uchun.','''Data'' menyusidagi Filter opsiyasida.','+, -, *, /, SUM, AVERAGE, MIN, MAX.'], 1) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (6, 'Hardware', 'BIOS ning to''liq nomi nima?', array['Kompyuter komponentlarini ulash va ularning o''rtasida aloqa ta''minlash uchun.','Basic Input/Output System.','CPU operatsiyasini to''xtatib, ustuvor vazifani bajarish signalini beradi.','CPU ichida bir nechta threadlarni bir vaqtda ishlashini ta''minlash.'], 1) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (7, 'Hardware', 'BIOS qanday tizimga tegishli?', array['Kompyuterning firmware (past darajali dasturiy ta''minot) qismiga.','Resurslarni (CPU, xotira, disk, tarmoq) boshqarish.','Ona plata ichida komponentlar o''rtasidagi ma''lumot almashinuvini boshqaradi.','CPU ichida bir nechta threadlarni bir vaqtda ishlashini ta''minlash.'], 0) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (8, 'Cloud', 'Bulutli texnologiyalar nima imkoniyat beradi?', array['SaaS (Software as a Service) va IaaS (Infrastructure as a Service).','Internet orqali saqlash, ishlash va ilovalardan foydalanish imkonini yaratadi.','Faylni tanlab Delete yoki Trash''ga ko''chiriladi.','Google''ning bulutli saqlash xizmati.'], 1) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (9, 'Cloud', 'Bulutli texnologiyalarda faylni saqlash uchun qaysi xizmat ishlatiladi?', array['Internet va brauzer orqali (cloud''da).','Google Drive, Dropbox, OneDrive kabilar.','Bulutli saqlash va fayl sinxronizatsiyasi xizmati.','Resurslarni osongina kengaytirish, xarajatni kamaytirish va samaradorlikni oshirish.'], 1) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (10, 'Hardware', 'Chipset kompyuterda nima vazifani bajaradi?', array['Kompyuter resurslarini boshqaruvchi dasturiy ta''minot.','CPU ichida bir nechta threadlarni bir vaqtda ishlashini ta''minlash.','Ona plata ichida komponentlar o''rtasidagi ma''lumot almashinuvini boshqaradi.','CPU''siz I/O qurilmalar bilan xotira orasida to''g''ridan-to''g''ri ma''lumot uzatadi.'], 2) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (11, 'Cloud', 'Cloud backup tizimi qanday ishlaydi?', array['SaaS (Software as a Service) va IaaS (Infrastructure as a Service).','Internet va brauzer orqali (cloud''da).','Fayllarni avtomatik tarzda masofaviy serverga yuklaydi va zaxira qiladi.','Google Drive, Dropbox, OneDrive kabilar.'], 2) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (12, 'Cloud', 'Cloud Computing qanday asosiy afzallikni beradi?', array['SaaS (Software as a Service) va IaaS (Infrastructure as a Service).','Resurslarni osongina kengaytirish, xarajatni kamaytirish va samaradorlikni oshirish.','Google''ning bulutli saqlash xizmati.','Faylni tanlab Delete yoki Trash''ga ko''chiriladi.'], 1) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (13, 'Cloud', 'Cloud texnologiyada ''scalability'' nimani anglatadi?', array['Resurslarni (CPU, RAM, disk) dinamik ravishda oshirish yoki kamaytirish.','Resurslarni osongina kengaytirish, xarajatni kamaytirish va samaradorlikni oshirish.','Fayllarni avtomatik tarzda masofaviy serverga yuklaydi va zaxira qiladi.','Fayl ustiga o''ng tugma → Share, link orqali.'], 0) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (14, 'Hardware', 'CMOS batareya kompyuterning qaysi komponentini saqlab turadi?', array['Doimiy ravishda ma''lumot saqlash.','BIOS sozlamalari va tizim soatini.','CPU operatsiyasini to''xtatib, ustuvor vazifani bajarish signalini beradi.','Resurslarni (CPU, xotira, disk, tarmoq) boshqarish.'], 1) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (15, 'Excel', 'Conditional Formatting qanday vazifani bajaradi?', array['Excel hujjatidagi alohida varaqlar (tabs).','Katta hajmdagi ma''lumotni tahlil qilish va ko''rgazmali hisobot berish uchun.','Takrorlanuvchi vazifalarni avtomatlashtirish uchun.','Ma''lumotga shart asosida rang, shrift va fon formatini belgilash.'], 3) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (16, 'Word', 'Ctrl + B tugmalari nima vazifani bajaradi?', array['Matnni qalin (bold) qiladi.','Bir xil hujjatga har xil ma''lumotlarni joylab, ommaviy yuborish imkonini beradi.','Ctrl + S yoki menyuda ''Save'' opsiyasini tanlash orqali.','''Home'' menyusi ichida, yoki Ctrl + H yordamida chaqiriladi.'], 0) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (17, 'Umumiy', 'Ctrl + C va Ctrl + V nima vazifani bajaradi?', array['Shartga ko''ra farqli natijalar qaytaradi (misol: =IF(A1>0,"Musbat","Manfiy")).','Xotira xatolarini aniqlash va tuzatish orqali ishonchlilikni oshiradi.','Insert → Chart menyusidan.','Ma''lumotni nusxalash (copy) va joylashtirish (paste).'], 3) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (18, 'Word', 'Ctrl + S tugmalari nima uchun ishlatiladi?', array['Word''da Insert → Page Number opsiyasidan.','Onlayn matn hujjatlarini yaratish va birgalikda tahrirlash.','Hujjatni saqlash uchun.','Matn tahrirlash, formatlash, sahifalash.'], 2) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (19, 'Umumiy', 'Ctrl + Z qanday vazifa bajaradi?', array['Xotira xatolarini aniqlash va tuzatish orqali ishonchlilikni oshiradi.','Ma''lumotni nusxalash (copy) va joylashtirish (paste).','.doc, .docx, .odt, .rtf, .txt, .pdf, .xls va boshqalar.','Oxirgi amalni bekor qilish (undo).'], 3) on conflict do nothing;
insert into public.questions (number, category, question, options, correct_index) values (20, 'I/O', 'Data Validation nima vazifani bajaradi?', array['Sichqoncha yoki klaviaturaning strelka tugmalari.','Ma''lumot kiritishda formalar va qiymatlarni cheklash uchun.','Kiritish (input) qurilmalariga.','Chiqish (output) qurilmasi.'], 1) on conflict do nothing;
